private async sendNotification(params: {
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  userId?: string;
}): Promise<void> {
  // Queue notifications per-recipient to guarantee delivery order.
  // Without this, concurrent event emissions (e.g., order:created and
  // order:status-changed fired without awaiting) can cause adapter.send()
  // calls to race, delivering notifications out of order.
  const queueKey = params.recipient;
  const previous = this.sendQueues.get(queueKey) ?? Promise.resolve();
  const current = previous.then(() => this.processSend(params));
  this.sendQueues.set(queueKey, current);
  return current;
}

